}

&-end {
  width: 100%;
  display: flex;
  flex-direction: row;
  flex-wrap: wrap;
  align-items: center;
  padding: 0 @h-spacing-large;
  padding: 0 var(--am-footer-divider-paddingLR, @h-spacing-large);
  font-size: @font-size-content;
  font-size: var(--am-footer-content-fontSize, @font-size-content);
